import React, { useEffect, useState } from "react";
import { MapContainer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);

  useEffect(() => {
    const ws = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        setBuses(data.buses || []);
      } catch (err) {
        console.error("Failed to parse WS message:", err);
      }
    };

    ws.onopen = () => console.log("[WS] Connected");
    ws.onclose = () => console.log("[WS] Disconnected");

    return () => ws.close();
  }, []);

  return (
    <div style={{ height: "100vh", width: "100%" }}>
      <MapContainer
        center={[40.7128, -74.0060]} // NYC center
        zoom={12}
        style={{ height: "100%", width: "100%", background: "white" }} // White background
        zoomControl={true}
      >
        {buses.map((bus) => (
          <CircleMarker
            key={bus.id}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={bus.status === "Running" ? "green" : "red"} // Green = Running, Red = Ghost
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Route:</strong> {bus.route} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong> {bus.speed.toFixed(1)} mph
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
